import CustomCard from '../base/CustomCard';
import CollapsedText from '../base/CollapsedText';
import CustomButton from '../base/CustomButton';
import ReactPlayer from 'react-player';

function CollapsedVideoCard({ game }) {
  return (
    <>
     <CustomCard content={
        <ReactPlayer
          url={game.url}
          controls
          width='95%'
          height='95%'
          loop
          muted
        />
      }
        className="custom-card colored-card"
      />

      <CustomCard content={
        <CollapsedText
          title={game.title}
          description={game.description}
          content={
            <CustomButton
              buttonLabel={game.buttonLabel}
              onClickNavigate={game.onClickNavigate}
            />
          }
        />
      }
        className="custom-card colored-card width-full"
      />
    </>
  );
}

export default CollapsedVideoCard;
